int maximum( int a, int b, int c) {
    int k = (a <= b) ? b : a;
    return (c >= k) ? c : k;
}

// Helper to access local memory safely
inline int& score_val(std::vector<int>& l, int i, int j) {
    return l[j + i * (BLOCK_SIZE+1)];
}
inline int& ref_val(std::vector<int>& l, int i, int j) {
    return l[j + i * BLOCK_SIZE];
}

void nw_kernel1(int bx, int blk,
                int *reference_d, 
                int *input_itemsets_d, 
                int *output_itemsets_d, 
                int cols,
                int penalty,
                int block_width,
                int worksize,
                int offset_r,
                int offset_c)
{  
    // Use vector to avoid stack overflow and ensure proper allocation per group
    std::vector<int> input_itemsets_l((BLOCK_SIZE+1)*(BLOCK_SIZE+1));
    std::vector<int> reference_l(BLOCK_SIZE * BLOCK_SIZE);

    int base = offset_r * cols + offset_c;
    int b_index_x = bx;
    int b_index_y = blk - 1 - bx;

    // Calculate base indices for the block in the global arrays
    // The original code: index = base + cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + tx + (cols + 1);
    // Note: 'tx' varies per thread. The base part without tx is:
    int block_base = base + cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x;

    #pragma omp parallel num_threads(BLOCK_SIZE) shared(input_itemsets_l, reference_l)
    {
        int tx = omp_get_thread_num();

        // Recalculate indices per thread as in original
        int index   = block_base + tx + (cols + 1);
        int index_n = block_base + tx + 1;
        int index_w = block_base + cols; // tx is not added here in original: index_w = ... + (cols)
        int index_nw= block_base;       // tx is not added here

        // Original: if (0 == tx) SCORE(tx, 0) = input_itemsets_d[index_nw + tx];
        // index_nw + tx = block_base + tx
        if (0 == tx){
            score_val(input_itemsets_l, tx, 0) = input_itemsets_d[block_base + tx];
        }

        #pragma omp barrier

        // Original: REF(ty, tx) = reference_d[index + cols * ty];
        // index = block_base + tx + cols + 1
        for (int ty = 0; ty < BLOCK_SIZE; ty++) {
            ref_val(reference_l, ty, tx) = reference_d[index + cols * ty];
        }

        #pragma omp barrier

        // Original: SCORE((tx + 1), 0) = input_itemsets_d[index_w + cols * tx];
        // index_w = block_base + cols
        score_val(input_itemsets_l, tx + 1, 0) = input_itemsets_d[index_w + cols * tx];

        #pragma omp barrier

        // Original: SCORE(0, (tx + 1)) = input_itemsets_d[index_n];
        // index_n = block_base + tx + 1
        score_val(input_itemsets_l, 0, tx + 1) = input_itemsets_d[index_n];

        #pragma omp barrier

        for(int m = 0; m < BLOCK_SIZE; m++){
            if (m >= tx){
                int t_index_x = tx + 1;
                int t_index_y = m - tx + 1;

                int val_diag = score_val(input_itemsets_l, t_index_y-1, t_index_x-1) + ref_val(reference_l, t_index_y-1, t_index_x-1);
                int val_up   = score_val(input_itemsets_l, t_index_y, t_index_x-1) - penalty;
                int val_left = score_val(input_itemsets_l, t_index_y-1, t_index_x) - penalty;

                score_val(input_itemsets_l, t_index_y, t_index_x) = maximum(val_diag, val_up, val_left);
            }
            #pragma omp barrier
        }

        #pragma omp barrier

        for(int m = BLOCK_SIZE - 2; m >= 0; m--){
            if (tx <= m){
                int t_index_x = tx + BLOCK_SIZE - m;
                int t_index_y = BLOCK_SIZE - tx;

                int val_diag = score_val(input_itemsets_l, t_index_y-1, t_index_x-1) + ref_val(reference_l, t_index_y-1, t_index_x-1);
                int val_up   = score_val(input_itemsets_l, t_index_y, t_index_x-1) - penalty;
                int val_left = score_val(input_itemsets_l, t_index_y-1, t_index_x) - penalty;

                score_val(input_itemsets_l, t_index_y, t_index_x) = maximum(val_diag, val_up, val_left);
            }
            #pragma omp barrier
        }

        // Original: input_itemsets_d[index + cols * ty] = SCORE((ty+1), (tx+1));
        // index here is the thread-specific 'index' calculated at start: block_base + tx + cols + 1
        for (int ty = 0; ty < BLOCK_SIZE; ty++) {
            score_val(input_itemsets_l, ty+1, tx+1) = input_itemsets_d[index + cols * ty]; // Wait, original writes TO global
            // Correction: Original reads FROM local, writes TO global?
            // Original: input_itemsets_d[index + cols * ty] = SCORE((ty+1), (tx+1));
            // Yes, writes to global.
            input_itemsets_d[index + cols * ty] = score_val(input_itemsets_l, ty+1, tx+1);
        }
    }
}

void nw_kernel2(int bx, int blk,
                int *reference_d, 
                int *input_itemsets_d, 
                int *output_itemsets_d, 
                int cols,
                int penalty,
                int block_width,
                int worksize,
                int offset_r,
                int offset_c)
{  
    std::vector<int> input_itemsets_l((BLOCK_SIZE+1)*(BLOCK_SIZE+1));
    std::vector<int> reference_l(BLOCK_SIZE * BLOCK_SIZE);

    int base = offset_r * cols + offset_c;
    int b_index_x = bx + block_width - blk;
    int b_index_y = block_width - bx - 1;

    int block_base = base + cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x;

    #pragma omp parallel num_threads(BLOCK_SIZE) shared(input_itemsets_l, reference_l)
    {
        int tx = omp_get_thread_num();

        int index   = block_base + tx + (cols + 1);
        int index_n = block_base + tx + 1;
        int index_w = block_base + cols;
        int index_nw= block_base;

        if (tx == 0)
            score_val(input_itemsets_l, tx, 0) = input_itemsets_d[index_nw];

        for (int ty = 0; ty < BLOCK_SIZE; ty++) {
            ref_val(reference_l, ty, tx) = reference_d[index + cols * ty];
        }

        #pragma omp barrier

        score_val(input_itemsets_l, tx + 1, 0) = input_itemsets_d[index_w + cols * tx];

        #pragma omp barrier

        score_val(input_itemsets_l, 0, tx + 1) = input_itemsets_d[index_n];

        #pragma omp barrier

        for(int m = 0; m < BLOCK_SIZE; m++){
            if (tx <= m){
                int t_index_x = tx + 1;
                int t_index_y = m - tx + 1;

                int val_diag = score_val(input_itemsets_l, t_index_y-1, t_index_x-1) + ref_val(reference_l, t_index_y-1, t_index_x-1);
                int val_up   = score_val(input_itemsets_l, t_index_y, t_index_x-1) - penalty;
                int val_left = score_val(input_itemsets_l, t_index_y-1, t_index_x) - penalty;

                score_val(input_itemsets_l, t_index_y, t_index_x) = maximum(val_diag, val_up, val_left);
            }
            #pragma omp barrier
        }

        for(int m = BLOCK_SIZE - 2; m >= 0; m--){
            if (m >= tx){
                int t_index_x = tx + BLOCK_SIZE - m;
                int t_index_y = BLOCK_SIZE - tx;

                int val_diag = score_val(input_itemsets_l, t_index_y-1, t_index_x-1) + ref_val(reference_l, t_index_y-1, t_index_x-1);
                int val_up   = score_val(input_itemsets_l, t_index_y, t_index_x-1) - penalty;
                int val_left = score_val(input_itemsets_l, t_index_y-1, t_index_x) - penalty;

                score_val(input_itemsets_l, t_index_y, t_index_x) = maximum(val_diag, val_up, val_left);
            }
            #pragma omp barrier
        }

        for (int ty = 0; ty < BLOCK_SIZE; ty++) {
            input_itemsets_d[index + ty * cols] = score_val(input_itemsets_l, ty+1, tx+1);
        }
    }
}

double gettime() {
  struct timeval t;
  gettimeofday(&t,NULL);
  return t.tv_sec+t.tv_usec*1e-6;
}

void usage(int argc, char **argv)
{
	fprintf(stderr, "Usage: %s <max_rows/max_cols> <penalty> [-p platform] [-d device]\n", argv[0]);
	fprintf(stderr, "\t<dimension>  - x and y dimensions\n");
	fprintf(stderr, "\t<penalty> - penalty(positive integer)\n");
	fprintf(stderr, "\t<file> - filename\n");
	fprintf(stderr, "\t[platform] - platform id\n");
	fprintf(stderr, "\t[device] - device id\n");
	exit(1);
}

